import{_ as a,o,c as t,a3 as i}from"./chunks/framework.Qwh7I5Yr.js";const m=JSON.parse('{"title":"VS Code Integration","description":"","frontmatter":{},"headers":[],"relativePath":"vscode.md","filePath":"vscode.md","lastUpdated":null}'),s={name:"vscode.md"};function n(d,e,l,c,r,p){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="VS-Code-Integration" tabindex="-1">VS Code Integration <a class="header-anchor" href="#VS-Code-Integration" aria-label="Permalink to &quot;VS Code Integration {#VS-Code-Integration}&quot;">​</a></h1><p>Kaimon.jl provides deep integration with Visual Studio Code through the <a href="https://marketplace.visualstudio.com/items?itemName=nicolo-ribaudo.remote-control" target="_blank" rel="noreferrer">VS Code Remote Control</a> extension. This enables bidirectional communication between the Julia REPL and VS Code, powering features like command execution, debugging, and file navigation.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><p>Install the <strong>Remote Control</strong> extension in VS Code. Kaimon detects the extension automatically when running inside a VS Code terminal.</p><h3 id="Allowed-Commands" tabindex="-1">Allowed Commands <a class="header-anchor" href="#Allowed-Commands" aria-label="Permalink to &quot;Allowed Commands {#Allowed-Commands}&quot;">​</a></h3><p>VS Code commands must be explicitly allowlisted in your <code>.vscode/settings.json</code> before they can be executed via MCP:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;vscode-remote-control.allowedCommands&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;workbench.action.files.saveAll&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;editor.action.formatDocument&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;workbench.action.debug.start&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Use <a href="/Kaimon.jl/v1.2.1/vscode#list_vscode_commands"><code>list_vscode_commands</code></a> to see which commands are currently allowed.</p><h2 id="Command-Execution" tabindex="-1">Command Execution <a class="header-anchor" href="#Command-Execution" aria-label="Permalink to &quot;Command Execution {#Command-Execution}&quot;">​</a></h2><h3 id="execute_vscode_command" tabindex="-1"><code>execute_vscode_command</code> <a class="header-anchor" href="#execute_vscode_command" aria-label="Permalink to &quot;`execute_vscode_command` {#execute_vscode_command}&quot;">​</a></h3><p>Run any allowlisted VS Code command from Julia or an MCP client:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>execute_vscode_command(&quot;workbench.action.files.saveAll&quot;)</span></span></code></pre></div><p>Set <code>wait_for_response=true</code> to get the return value from the command (with an optional timeout):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>execute_vscode_command(&quot;editor.action.clipboardCopyAction&quot;, wait_for_response=true, timeout=5)</span></span></code></pre></div><p>Arguments can be passed as a JSON-encoded array via the <code>args</code> parameter.</p><h3 id="list_vscode_commands" tabindex="-1"><code>list_vscode_commands</code> <a class="header-anchor" href="#list_vscode_commands" aria-label="Permalink to &quot;`list_vscode_commands` {#list_vscode_commands}&quot;">​</a></h3><p>Returns the list of commands configured in <code>.vscode/settings.json</code> under <code>vscode-remote-control.allowedCommands</code>. Use this to discover which commands are available before calling <code>execute_vscode_command</code>.</p><h2 id="File-Navigation" tabindex="-1">File Navigation <a class="header-anchor" href="#File-Navigation" aria-label="Permalink to &quot;File Navigation {#File-Navigation}&quot;">​</a></h2><h3 id="navigate_to_file" tabindex="-1"><code>navigate_to_file</code> <a class="header-anchor" href="#navigate_to_file" aria-label="Permalink to &quot;`navigate_to_file` {#navigate_to_file}&quot;">​</a></h3><p>Open a file in VS Code at a specific line and column position:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>navigate_to_file(file_path=&quot;/path/to/file.jl&quot;, line=100, column=15)</span></span></code></pre></div><p>Both <code>line</code> and <code>column</code> are optional (1-indexed, default to 1). This is useful for jumping to search results, navigating code tours, or following up on <code>goto_definition</code> results.</p>',22)])])}const u=a(s,[["render",n]]);export{m as __pageData,u as default};
